        val children = nodes \ tagName
        if (children.isEmpty) None else Some(children)
      }
    }.flatMap { finalNodes =>
      finalNodes.headOption.map(_.text.trim)
    }
  }

  def extractAllSettings(config: Elem, path: String): List[String] = {
    (config \\ path).map(_.text.trim).toList
  }
}

